// Normalize webhook POST data into flat fields for downstream nodes
// _source defaults to 'webhook' — no Set node needed

const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;

  // Webhook v2: POST body fields are directly on $json
  // Also handle nested body wrapper just in case
  const subject = d.body?.subject || d.subject || '';
  const body = d.body?.body || d.bodyPreview || d.body || '';
  const from = d.body?.from || d.from || '';

  results.push({
    json: {
      _source: 'webhook',
      subject: typeof subject === 'string' ? subject : '',
      body: typeof body === 'string' ? body : '',
      from: typeof from === 'string' ? from : '',
      received_at: new Date().toISOString(),
    }
  });
}

return results;

// Extract structured disbursement data from normalized email fields

const items = $input.all();
const results = [];

for (const item of items) {
  const subject = item.json.subject || '';
  const body = item.json.body || '';
  const from = item.json.from || '';
  const source = item.json._source || 'webhook';

  // COMPANY NAME
  let company = 'Unknown Company';
  const companyMatch = subject.match(/[\u2013\u2014\-]\s*(.+)$/);
  if (companyMatch) company = companyMatch[1].trim();

  // AMOUNT
  let amount = 0;
  const amountMatch = body.match(/([\d,]+)\s*(?:MMK|Kyat)/i)
    || body.match(/(?:MMK|Kyat)\s*([\d,]+)/i)
    || subject.match(/([\d,]+)\s*(?:MMK|Kyat)/i);
  if (amountMatch) {
    amount = parseInt(amountMatch[1].replace(/,/g, ''), 10);
  }

  // TYPE
  const isOTC = /OTC/i.test(subject) || /OTC/i.test(body) || /over.the.counter/i.test(body);
  const type = isOTC ? 'SalaryToOTC' : 'SalaryToMA';

  // APPROVERS
  const approvals = [];
  const pattern = /(?:Approved by|authorized by|sign-off:?)\s+([^(]+?)\s*\(([^)]+)\)/gi;
  let match;
  while ((match = pattern.exec(body)) !== null) {
    const name = match[1].trim();
    const role = match[2].trim();
    if (!approvals.find(a => a.name === name)) {
      approvals.push({ name, role, status: 'Approved' });
    }
  }

  results.push({
    json: {
      _source: source,
      company,
      type,
      amount_requested: amount,
      amount_on_bank_slip: amount,
      currency: 'MMK',
      approvals,
      required_approvals: ['Sales HOD', 'Finance Manager'],
      body_preview: body.substring(0, 200),
      from_email: from,
      original_subject: subject,
      parsed_at: new Date().toISOString(),
    }
  });
}

return results;

// Check authority matrix + generate the dashboard URL

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  // AUTHORITY MATRIX CHECK
  const required = data.required_approvals || ['Sales HOD', 'Finance Manager'];
  const matrixResults = required.map(req => {
    const found = (data.approvals || []).find(a =>
      a.role.toLowerCase().includes(req.toLowerCase())
    );
    return {
      requiredRole: req,
      found: !!found,
      foundName: found ? found.name : 'MISSING',
    };
  });
  const matrixComplete = matrixResults.every(m => m.found);

  // SCENARIO DETECTION
  let scenario = 'NORMAL';
  if (data.amount_requested !== data.amount_on_bank_slip) {
    scenario = 'AMOUNT_MISMATCH';
  } else if (!matrixComplete) {
    scenario = 'MISSING_APPROVAL';
  }

  // BUILD TICKET PAYLOAD
  const ticket = {
    company: data.company,
    type: data.type,
    amount_requested: data.amount_requested,
    amount_on_bank_slip: data.amount_on_bank_slip,
    currency: data.currency,
    approvals: data.approvals,
    required_approvals: data.required_approvals,
    body_preview: data.body_preview,
    parsed_at: data.parsed_at,
    scenario,
    approval_matrix_complete: matrixComplete,
  };

  // GENERATE DASHBOARD URL
  const encoded = Buffer.from(JSON.stringify(ticket)).toString('base64');
  const dashboardUrl = `https://wave-emi-dashboard.vercel.app/?n8n_ticket=${encoded}`;

  results.push({
    json: {
      _source: data._source,
      dashboard_url: dashboardUrl,
      company: data.company,
      amount: data.amount_requested,
      type: data.type,
      scenario,
      matrix_complete: matrixComplete,
      matrix_details: matrixResults,
      from_email: data.from_email,
      original_subject: data.original_subject,
    }
  });
}

return results;
